    message = log.get('message', '')

    if level == 'ERROR':
        return colored(message, 'red')
    elif level == 'WARNING':
        return colored(message, 'yellow')
    elif level == 'INFO':
        return colored(message, 'green')
    elif level == 'DEBUG':
